  "teamObjective": {
    "type": "transfer_lead_to_partner",
    "explanation": "With only low non-trump cards, the best opening play is a low single to let the partner win the trick cheaply and take control, rather than trying to force a lead myself."
  },
  "partnerBelief": {
    "summary": "No specific belief about partner's cards; they are hidden.",
